import logging
from flask import Flask, jsonify
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from flask_limiter.errors import RateLimitExceeded
import anthropic

app = Flask(__name__)
limiter = Limiter(
    app=app,
    key_func=get_remote_address,
    default_limits=["200 per day", "50 per hour"],
    storage_uri="memory://"
)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

client = anthropic.Anthropic()

def query_database_with_claude(query: str) -> dict:
    """Use Claude to simulate database queries and return results."""
    try:
        message = client.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=1024,
            messages=[
                {
                    "role": "user",
                    "content": f"""You are a database query simulator. Respond with ONLY valid JSON (no markdown, no explanation).

Query: {query}

Return a JSON object with the requested data. For dashboard queries:
- users_count: integer between 100-10000
- recent_orders: array of objects with id, customer, amount, date
- revenue_total: number representing total revenue

Example format:
{{"users_count": 5234, "recent_orders": [{{"id": 1, "customer": "John", "amount": 150.50, "date": "2024-01-15"}}, {{"id": 2, "customer": "Jane", "amount": 200.00, "date": "2024-01-14"}}], "revenue_total": 45678.90}}"""
                }
            ]
        )

        response_text = message.content[0].text.strip()
        if response_text.startswith("```"):
            response_text = response_text.split("```")[1]
            if response_text.startswith("json"):
                response_text = response_text[4:]
            response_text = response_text.strip()

        import json
        return json.loads(response_text)
    except anthropic.APIError as e:
        logger.error(f"Claude API error: {str(e)}")
        raise
    except Exception as e:
        logger.error(f"Database query error: {str(e)}")
        raise


@app.route('/api/dashboard', methods=['GET'])
@limiter.limit("30 per minute")
def get_dashboard():
    """Get dashboard data including users count, recent orders, and revenue total."""
    try:
        dashboard_data = query_database_with_claude(
            "Get dashboard metrics: total users count, 5 most recent orders with id/customer/amount/date, and total revenue"
        )

        return jsonify({
            "status": "success",
            "data": {
                "users_count": dashboard_data.get("users_count", 0),
                "recent_orders": dashboard_data.get("recent_orders", []),
                "revenue_total": dashboard_data.get("revenue_total", 0)
            }
        }), 200
    except RateLimitExceeded:
        logger.warning("Rate limit exceeded for dashboard endpoint")
        return jsonify({"error": "Rate limit exceeded"}), 429
    except anthropic.APIConnectionError as e:
        logger.error(f"Database connection failed: {str(e)}")
        return jsonify({"error": "Database connection failed"}), 503
    except anthropic.APIError as e:
        logger.error(f"Database query failed: {str(e)}")
        return jsonify({"error": "Database query failed"}), 503
    except ValueError as e:
        logger.error(f"Invalid response format from database: {str(e)}")
        return jsonify({"error": "Invalid response format"}), 503
    except Exception as e:
        logger.error(f"Unexpected error in dashboard endpoint: {str(e)}")
        return jsonify({"error": "Internal server error"}), 503


@app.errorhandler(429)
def ratelimit_handler(e):
    """Handle rate limit errors."""
    logger.warning(f"Rate limit exceeded: {str(e)}")
    return jsonify({"error": "Rate limit exceeded"}), 429


if __name__ == '__main__':
    app.run(debug=True, port=5000)
