import logging
from flask import Flask, jsonify
from flask_sqlalchemy import SQLAlchemy
from sqlalchemy import text
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///dashboard.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

db = SQLAlchemy(app)
logger = logging.getLogger(__name__)


class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)


class Order(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    amount = db.Column(db.Float, nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)


@app.route('/api/dashboard', methods=['GET'])
def get_dashboard():
    try:
        users_count = db.session.query(User).count()
    except Exception as e:
        logger.error(f"Database error querying users count: {str(e)}")
        return jsonify({"error": "Database connection failed"}), 503

    try:
        recent_orders = db.session.query(Order).order_by(Order.created_at.desc()).limit(10).all()
    except Exception as e:
        logger.error(f"Database error querying recent orders: {str(e)}")
        return jsonify({"error": "Database connection failed"}), 503

    try:
        revenue_result = db.session.query(db.func.sum(Order.amount)).scalar()
        revenue_total = float(revenue_result) if revenue_result else 0.0
    except Exception as e:
        logger.error(f"Database error querying revenue total: {str(e)}")
        return jsonify({"error": "Database connection failed"}), 503

    try:
        orders_data = [
            {
                'id': order.id,
                'user_id': order.user_id,
                'amount': order.amount,
                'created_at': order.created_at.isoformat() if order.created_at else None
            }
            for order in recent_orders
        ]
    except Exception as e:
        logger.error(f"Error processing orders data: {str(e)}")
        return jsonify({"error": "Data processing failed"}), 503

    dashboard_data = {
        'users_count': users_count,
        'recent_orders': orders_data,
        'revenue_total': revenue_total,
        'timestamp': datetime.utcnow().isoformat()
    }

    return jsonify(dashboard_data), 200


@app.route('/health', methods=['GET'])
def health_check():
    try:
        db.session.execute(text('SELECT 1'))
        return jsonify({"status": "healthy"}), 200
    except Exception as e:
        logger.error(f"Health check failed: {str(e)}")
        return jsonify({"error": "Database connection failed"}), 503


if __name__ == '__main__':
    with app.app_context():
        db.create_all()
        app.run(debug=True)
